package com.example.loginfeature;

public class Constants {
    public static final String PREFS_NAME = "LoginPrefs";
    public static final String KEY_EMAIL = "email";
    public static final String KEY_AUTH_TOKEN = "authToken"; // For a real app, this would be a real token
}

// LoginActivity.java
package com.example.loginfeature;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailEditText;
    private EditText passwordEditText;
    private Button loginButton;
    private SharedPreferences sharedPreferences;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        // Initialize SharedPreferences
        sharedPreferences = getSharedPreferences(Constants.PREFS_NAME, Context.MODE_PRIVATE);

        // Check if user is already logged in (credentials exist in SharedPreferences)
        if (sharedPreferences.contains(Constants.KEY_EMAIL) && sharedPreferences.contains(Constants.KEY_AUTH_TOKEN)) {
            // User is already logged in, navigate to MainActivity
            startActivity(new Intent(LoginActivity.this, MainActivity.class));
            finish(); // Close LoginActivity so user can't navigate back to it
            return; // Important to return after finishing activity
        }

        // Initialize UI components
        emailEditText = findViewById(R.id.emailEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        loginButton = findViewById(R.id.loginButton);

        // Set login button click listener
        loginButton.setOnClickListener(v -> {
            String email = emailEditText.getText().toString().trim();
            String password = passwordEditText.getText().toString().trim();

            if (email.isEmpty() || password.isEmpty()) {
                Toast.makeText(LoginActivity.this, "Please enter email and password", Toast.LENGTH_SHORT).show();
                return;
            }

            // --- Simulate a login process ---
            // In a real application, you would send these credentials to a server
            // and receive a response, including an auth token upon success.
            if (email.equals("test@example.com") && password.equals("password")) {
                // Simulate successful login
                String authToken = "mock_auth_token_12345"; // This would come from your server

                // Save credentials to SharedPreferences
                SharedPreferences.Editor editor = sharedPreferences.edit();
                editor.putString(Constants.KEY_EMAIL, email);
                editor.putString(Constants.KEY_AUTH_TOKEN, authToken);
                editor.apply(); // Use apply() for asynchronous saving; commit() for synchronous

                Toast.makeText(LoginActivity.this, "Login Successful!", Toast.LENGTH_SHORT).show();

                // Navigate to MainActivity
                startActivity(new Intent(LoginActivity.this, MainActivity.class));
                finish(); // Close LoginActivity
            } else {
                // Simulate failed login
                Toast.makeText(LoginActivity.this, "Invalid email or password", Toast.LENGTH_SHORT).show();
            }
        });
    }
}

// MainActivity.java
package com.example.loginfeature;

import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private TextView welcomeTextView;
    private Button logoutButton;
    private SharedPreferences sharedPreferences;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Initialize SharedPreferences
        sharedPreferences = getSharedPreferences(Constants.PREFS_NAME, Context.MODE_PRIVATE);

        // Initialize UI components
        welcomeTextView = findViewById(R.id.welcomeTextView);
        logoutButton = findViewById(R.id.logoutButton);

        // Retrieve and display the logged-in user's email
        String email = sharedPreferences.getString(Constants.KEY_EMAIL, "Guest");
        welcomeTextView.setText("Welcome, " + email + "!");

        // Set logout button click listener
        logoutButton.setOnClickListener(v -> {
            // Clear all saved credentials from SharedPreferences
            SharedPreferences.Editor editor = sharedPreferences.edit();
            editor.clear(); // Clears all key-value pairs in this specific SharedPreferences file
            editor.apply();

            Toast.makeText(MainActivity.this, "Logged out successfully", Toast.LENGTH_SHORT).show();

            // Navigate back to LoginActivity
            startActivity(new Intent(MainActivity.this, LoginActivity.class));
            finish(); // Close MainActivity so user can't navigate back to it
        });
    }
}

